+
+export const generateVideoWithPollingTool = tool({
+  description:
+    'Generate a video using the specified model. This handles the complete workflow: creates the generation, polls for completion, and returns the final result. The final output contains the predictionId and requestLink, return a custom video element in the markdown like [BUNDLED##{"type": "video", "data": {"predictionId": "{{ predictionId }}", "requestLink": "{{ requestLink }}"}}](https://bundled.design/)',
+  inputSchema: z.object({
+    prompt: z
+      .string()
