+    modelName: z.string().describe("The video model ID to use for generation"),
+    image_url: z
+      .string()
+      .optional()
+      .describe("Optional input image URL for image-to-video generation"),
+    aspect_ratio: z
+      .string()
+      .optional()
+      .describe(
+        'Video aspect ratio (e.g., "16:9", "9:16", "1:1"). Defaults to "16:9"',
+      ),
+    duration: z
+      .string()
+      .optional()
+      .describe(
+        'Video duration (e.g., "5", "8s"). If omitted, sensible defaults are applied per model.',
+      ),
+    resolution: z
+      .string()
+      .optional()
+      .describe(
+        'Video resolution (e.g., "720p", "1080p"). If omitted, sensible defaults are applied per model.',
+      ),
+    negative_prompt: z
+      .string()
+      .optional()
+      .describe("Optional negative prompt to avoid certain artifacts."),
+    generate_audio: z
+      .boolean()
+      .optional()
+      .default(true)
+      .describe(
+        "Whether to generate audio with the video. Defaults to true. Required for VEO 3.1 and similar models.",
+      ),
+  }),
+  execute: async ({
+    prompt,
+    modelName,
+    image_url,
+    aspect_ratio = "16:9",
+    duration,
+    resolution,
+    negative_prompt,
+    generate_audio = true,
+  }) => {
+    const res = await generateVideoWithPollingAction({
+      prompt,
+      modelName,
+      image_url,
+      aspect_ratio,
+      duration,
+      resolution,
+      negative_prompt,
+      generate_audio,
+    });
+    return res;
+  },
+});
