+/**
+ * Agent stream utility functions
+ *
+ * Helper functions for working with UI message streams from AI SDK agents.
+ */
+
+import type { UIMessage } from "ai";
+
+export function extractTextFromUiMessage(message: UIMessage): string | null {
+  const textPart = message.parts?.find(
+    (part) => part.type === "text" && "text" in part && part.text,
+  );
+  return textPart && "text" in textPart ? textPart.text : null;
+}
+
+export function extractLatestUserTextFromUiMessages(
+  messages: UIMessage[],
+): string | null {
+  for (let i = messages.length - 1; i >= 0; i--) {
+    const msg = messages[i];
+    if (msg.role === "user") {
+      const text = extractTextFromUiMessage(msg);
+      if (text) return text;
+    }
+  }
+  return null;
+}
+
+export function summarizeParts(parts: UIMessage["parts"]): string {
+  if (!parts || parts.length === 0) return "empty";
+
+  const summaries: string[] = [];
+  for (const part of parts) {
+    switch (part.type) {
+      case "text":
+        summaries.push("text");
+        break;
+      case "reasoning":
+        summaries.push("reasoning");
+        break;
+      case "file":
+        summaries.push("file");
+        break;
+      case "source-url":
+        summaries.push("source-url");
+        break;
+      case "source-document":
+        summaries.push("source-doc");
+        break;
+      case "step-start":
+        summaries.push("step");
+        break;
+      case "dynamic-tool":
+        summaries.push("dynamic-tool");
+        break;
+      default:
+        if (part.type.startsWith("tool-")) {
+          summaries.push("tool");
+        } else if (part.type.startsWith("data-")) {
+          summaries.push("data");
+        } else {
+          summaries.push("unknown");
+        }
+    }
+  }
+  return summaries.join(",");
+}
+
+export function getContinuationMessageId(
+  message: UIMessage,
+  previousMessages: UIMessage[],
+): { continuationId: string | undefined; messages: UIMessage[] } {
+  let continuationId: string | undefined;
+  let messages: UIMessage[];
+
+  if (message.role === "user") {
+    messages = [...previousMessages, message];
+  } else if (message.role === "assistant") {
+    continuationId = message.id;
+    messages = previousMessages;
+  } else {
+    messages = [...previousMessages, message];
+  }
+
+  return { continuationId, messages };
+}
