     4→  updateActiveTrace,
     5→} from "@langfuse/tracing";
     6→import { trace } from "@opentelemetry/api";
     7→import {
     8→  createAgentUIStreamResponse,
     9→  createUIMessageStream,
    10→  createUIMessageStreamResponse,
    11→  TypeValidationError,
    12→  type UIMessage,
    13→  validateUIMessages,
    14→} from "ai";
    15→import type { NextRequest } from "next/server";
    16→import { after } from "next/server";
    17→import { authenticateUser } from "@/lib/auth/utils";
    18→import {
    19→  type MediaAgentCallOptions,
    20→  mediaAgent,
    21→  mediaAgentTools,
    22→} from "@/lib/agents/media-agent";
    23→import {
    24→  createChat,
    25→  getChatById,
    26→} from "@/server/database/repo/postgress-repo-functions/chat.repo";
    27→import {
    28→  loadChatMessages,
    29→  saveChatMessage,
    30→} from "@/server/database/repo/postgress-repo-functions/chatMessage.repo";
    31→import { findProjectByIdForUser } from "@/server/database/repo/postgress-repo-functions/imageEditorProjects.repo";
    32→import logger from "@/utils/logger";
    33→import { langfuseSpanProcessor } from "../../../../../instrumentation";
    34→
    35→// Allow streaming up to 180s
    36→export const maxDuration = 180;
    37→
    38→const handler = async (req: NextRequest) => {
    39→  const requestId = crypto.randomUUID();
    40→  const { id: userId } = await authenticateUser(requestId);
    41→
    42→  // Get the last message, projectId, and optionally chatId from client
    43→  const {
    44→    message,
    45→    id: projectId,
    46→    chatId: clientChatId,
    47→    globalSystemInstructions,
    48→    modelSelection,
    49→  }: {
    50→    message: UIMessage;
    51→    id: string;
    52→    chatId?: string;
    53→    globalSystemInstructions?: string;
    54→    modelSelection?: {
    55→      isAutoMode: boolean;
    56→      imageModel: string | null;
    57→      videoModel: string | null;
    58→    };
    59→  } = await req.json();
    60→
    61→  // Log model selection for debugging
    62→  logger.info(`Model selection received: ${JSON.stringify(modelSelection)}`);
    63→
    64→  const initialTraceInput =
    65→    extractTextFromUiMessage(message) ??
    66→    `[${message.role}] ${summarizeParts(message.parts)}`;
    67→
    68→  try {
    69→    // Verify project exists and user owns it
    70→    const project = await findProjectByIdForUser({ projectId, userId });
    71→    if (!project) {
    72→      logger.error("Project not found or access denied");
    73→      return new Response(
    74→        JSON.stringify({ error: "Project not found or access denied" }),
    75→        { status: 403, headers: { "Content-Type": "application/json" } },
    76→      );
    77→    }
    78→
    79→    // Resolve or create chat
    80→    // Client always sends a chatId (either existing or pre-generated UUID)
    81→    let chat: Awaited<ReturnType<typeof getChatById>> | null = null;
    82→    let previousMessages: UIMessage[] = [];
    83→
    84→    if (!clientChatId) {
    85→      // Chat not found with provided chatId - create a new chat
    86→      logger.error("No chatId provided by client", {
    87→        requestId,
    88→        userId,
    89→        projectId,
    90→      });
    91→      return new Response(
    92→        JSON.stringify({
    93→          error:
    94→            "chatId is required but was not provided. This usually indicates an outdated or misconfigured client. Please refresh the page or update the client and try again.",
    95→        }),
    96→        {
    97→          status: 400,
    98→          headers: { "Content-Type": "application/json" },
    99→        },
   100→      );
   101→    }
   102→
   103→    // Update Langfuse trace with context (now that we have a chat/session id)
   104→    updateActiveTrace({
   105→      name: "agent-chat-message",
   106→      sessionId: clientChatId,
   107→      userId,
   108→      input: initialTraceInput,
   109→      metadata: {
   110→        projectId,
   111→        requestId,
   112→        isManualMode: modelSelection ? !modelSelection.isAutoMode : false,
   113→      },
   114→    });
   115→
   116→    updateActiveObservation({
   117→      input: initialTraceInput,
   118→    });
   119→
   120→    // Try to get existing chat
   121→    chat = await getChatById({ chatId: clientChatId, userId });
   122→
   123→    if (chat) {
   124→      // Existing chat - load messages
   125→      previousMessages = await loadChatMessages(chat.id, userId);
   126→    } else {
   127→      // No chatId provided - create a new chat
   128→
   129→      chat = await createChat({
   130→        id: clientChatId, // Use client's pre-generated ID
   131→        projectId,
   132→        userId,
   133→        title: "New Chat",
   134→      });
   135→
   136→      if (!chat) {
   137→        logger.error("Failed to create chat");
   138→        return new Response(
   139→          JSON.stringify({ error: "Failed to create chat" }),
   140→          { status: 500, headers: { "Content-Type": "application/json" } },
   141→        );
   142→      }
   143→      // No previous messages for new chat
   144→      previousMessages = [];
   145→    }
   146→
   147→    // Track continuation message ID to maintain consistent IDs across multi-step tool execution
   148→    // When client sends an assistant message (via sendAutomaticallyWhen), we reuse its ID
   149→    // so all steps share the same message ID (like DB upsert pattern)
   150→    let continuationMessageId: string | undefined;
   151→
   152→    // Build messages array for LLM based on incoming message role
   153→    let messages: UIMessage[];
   154→
   155→    if (message.role === "user") {
   156→      // User message: append to conversation history
   157→      messages = [...previousMessages, message];
   158→      logger.info(`User message received, total messages: ${messages.length}`);
   159→    } else if (message.role === "assistant") {
   160→      // Assistant message sent by client's sendAutomaticallyWhen
   161→      // Preserve the client's message ID for consistency
   162→      continuationMessageId = message.id;
   163→      // Use only previous messages (new assistant message will be generated)
   164→      messages = previousMessages;
   165→      logger.info(
   166→        `Assistant message received (auto-continuation), using ${messages.length} previous messages, continuationId: ${continuationMessageId}`,
   167→      );
   168→    } else {
   169→      // Unexpected role (system, etc.)
   170→      logger.warn(`Unexpected message role: ${message.role}`);
   171→      messages = [...previousMessages, message];
   172→    }
   173→
   174→    const bestTraceInput =
   175→      extractLatestUserTextFromUiMessages(messages) ?? initialTraceInput;
   176→
   177→    updateActiveObservation({ input: bestTraceInput });
   178→    updateActiveTrace({ input: bestTraceInput });
   179→
   180→    // Validate messages against tool schemas to ensure compatibility
   181→    let validatedMessages: UIMessage[];
   182→    try {
   183→      validatedMessages = await validateUIMessages({
   184→        messages,
   185→        // biome-ignore lint/suspicious/noExplicitAny: Because we have specific tightly typed tools types
   186→        tools: mediaAgentTools as any,
   187→      });
   188→    } catch (error) {
   189→      if (error instanceof TypeValidationError) {
   190→        // Log validation error for monitoring
   191→        logger.warn(
   192→          `Message validation failed, starting with only new message: ${error.message}`,
   193→        );
   194→        // If validation fails (e.g., old tool schemas), start fresh with just the new message
   195→        validatedMessages = [message];
   196→      } else {
   197→        throw error;
   198→      }
   199→    }
   200→
   201→    // Save user message to database immediately (before streaming)
   202→    // Assistant messages are saved in onFinish callback after streaming completes
   203→    if (message.role === "user") {
   204→      await saveChatMessage({ message, chatId: chat.id, userId });
   205→      logger.info(`User message saved: ${message.id}`);
   206→    }
