    11→const replicate = new Replicate({
    12→  auth: env.REPLICATE_API_TOKEN,
    13→});
    14→
    15→// Prevent Next.js / Vercel from caching responses
    16→replicate.fetch = (url, options) => {
    17→  return fetch(url, { cache: "no-store", ...options });
