    19→
    20→export type PredictionStatus =
    21→  | "starting"
    22→  | "processing"
    23→  | "succeeded"
    24→  | "failed"
    25→  | string;
    26→
    27→export type PredictionResponse = {
    28→  id: string;
    29→  status: PredictionStatus;
    30→  output?: unknown;
    31→  error?: string | null;
    32→  created_at?: string;
    33→  [key: string]: unknown;
    34→};
    35→
    36→export type PollOptions = {
    37→  baseUrl?: string; // e.g. process.env.NEXTAUTH_URL or http://localhost:3000
    38→  provider?: string; // e.g. 'replicate' | 'leonardo'
    39→  cookie?: string; // serialized cookie header to forward auth/session
    40→  maxAttempts?: number; // default 40
    41→  initialDelayMs?: number; // default 1000
    42→  maxDelayMs?: number; // default 10000
    43→  totalTimeoutMs?: number; // default 4 minutes
    44→  fixedInterval?: boolean; // if true, use fixed interval instead of exponential backoff
    45→};
    46→
    47→function sleep(ms: number): Promise<void> {
    48→  return new Promise((resolve) => setTimeout(resolve, ms));
    49→}
    50→
    51→function backoff(attempt: number, initial: number, maxDelay: number): number {
    52→  const delay = initial * 1.2 ** attempt;
    53→  return Math.min(delay, maxDelay);
    54→}
    55→
    56→export async function pollPrediction(
    57→  predictionId: string,
    58→  {
    59→    baseUrl = process.env.NEXT_PUBLIC_SERVER_URL || "http://localhost:3000",
    60→    provider = "replicate",
    61→    cookie,
    62→    maxAttempts = 20, // Reduced from 40
    63→    initialDelayMs = 2000, // Increased from 1000
    64→    maxDelayMs = 8000, // Reduced from 10000
    65→    totalTimeoutMs = 45 * 1000, // 45 seconds (leave 15s buffer for Vercel)
    66→    fixedInterval = false, // Use fixed interval instead of exponential backoff
    67→  }: PollOptions = {},
    68→): Promise<PredictionResponse> {
    69→  // [info] Start: polling prediction
    70→  logger.debug("[POLLING] 🚀 Starting prediction polling", {
    71→    predictionId,
    72→    provider,
    73→    baseUrl,
    74→    maxAttempts,
    75→    totalTimeoutMs: `${totalTimeoutMs / 1000}s`,
    76→    initialDelayMs,
    77→    fixedInterval,
    78→    mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
    79→  });
    80→
    81→  const start = Date.now();
    82→  let attempt = 0;
    83→
    84→  // [debug] Log polling configuration
    85→  logger.debug("[POLLING] 🔗 Polling configuration:", {
    86→    predictionId,
    87→    provider,
    88→    baseUrl,
    89→    directApiCall: provider === "replicate",
    90→  });
    91→
    92→  // Polling starts immediately (no initial delay)
    93→  // Direct Replicate API calls help reduce rate limiting by avoiding internal API overhead
    94→
    95→  while (attempt < maxAttempts && Date.now() - start < totalTimeoutMs) {
    96→    attempt += 1;
    97→
    98→    logger.debug(`[POLLING] 🔄 Attempt ${attempt}/${maxAttempts}`, {
    99→      predictionId,
   100→      provider,
   101→      timeElapsed: `${Math.round((Date.now() - start) / 1000)}s`,
   102→    });
   103→
   104→    try {
   105→      // [debug] Making direct API call to Replicate
   106→      logger.debug(
   107→        `[POLLING] 📡 Making direct API call to Replicate for prediction: ${predictionId}`,
   108→      );
   109→
   110→      let data: PredictionResponse;
   111→
   112→      if (provider === "replicate") {
   113→        // Call Replicate API directly (like the test route)
   114→        const prediction = await replicate.predictions.get(predictionId);
   115→        data = prediction as unknown as PredictionResponse;
   116→      } else {
   117→        // Fallback to internal API route for other providers
   118→        const pollUrl = `${baseUrl}/api/image/prediction/${encodeURIComponent(predictionId)}?provider=${encodeURIComponent(provider)}`;
   119→        logger.debug(`[POLLING] 📡 Using internal API route: ${pollUrl}`);
   120→
   121→        const res = await fetch(pollUrl, {
   122→          method: "GET",
   123→          headers: {
   124→            Accept: "application/json",
   125→            ...(cookie ? { Cookie: cookie } : {}),
   126→          },
   127→          cache: "no-store",
   128→        });
   129→
   130→        if (!res.ok) {
   131→          throw new Error(
   132→            `API request failed: ${res.status} ${res.statusText}`,
   133→          );
   134→        }
   135→
   136→        data = (await res.json()) as PredictionResponse;
   137→      }
   138→
   139→      // [debug] Log the full response structure
   140→      logger.debug("[POLLING] 📊 Full response data:", {
   141→        data,
   142→        dataKeys: Object.keys(data || {}),
   143→        dataType: typeof data,
   144→        isArray: Array.isArray(data),
   145→      });
   146→
   147→      // [debug] Polling JSON payload
   148→      logger.debug("[POLLING] 📋 Response summary:", {
   149→        status: data?.status,
   150→        id: data?.id,
   151→        hasOutput: !!data?.output,
   152→        hasError: !!data?.error,
   153→        created_at: data?.created_at,
   154→      });
   155→
   156→      if (data?.status === "succeeded") {
   157→        // [info] Completed: prediction succeeded
   158→        logger.debug(
   159→          "[POLLING] ✅ SUCCESS: Prediction completed successfully",
   160→          {
   161→            predictionId,
   162→            finalStatus: data.status,
   163→            outputCount: Array.isArray(data.output)
   164→              ? data.output.length
   165→              : "not array",
   166→            duration: `${Math.round((Date.now() - start) / 1000)}s`,
   167→          },
   168→        );
   169→        return data;
   170→      }
   171→
   172→      if (data?.status === "failed") {
   173→        // [error] Completed: prediction failed
   174→        logger.debug("[POLLING] ❌ FAILED: Prediction failed", {
   175→          predictionId,
   176→          error: data?.error,
   177→          finalStatus: data.status,
   178→          duration: `${Math.round((Date.now() - start) / 1000)}s`,
   179→        });
   180→        return data;
   181→      }
   182→
   183→      // Continue polling for other statuses
   184→      const delay = fixedInterval
   185→        ? initialDelayMs // Fixed interval: always use initialDelayMs
   186→        : backoff(attempt - 1, initialDelayMs, maxDelayMs); // Exponential backoff
   187→
   188→      const timeElapsed = Math.round((Date.now() - start) / 1000);
   189→      logger.debug(
   190→        `[POLLING] ⏳ Status: "${data?.status}" - continuing to poll...`,
   191→        {
   192→          predictionId,
   193→          attempt,
   194→          nextDelay: `${delay}ms (${delay / 1000}s)`,
   195→          mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
   196→          timeElapsed: `${timeElapsed}s`,
   197→          nextPollAt: `${timeElapsed + delay / 1000}s`,
   198→        },
   199→      );
   200→
   201→      logger.debug(
   202→        `[POLLING] ⏰ Sleeping for ${delay}ms (${delay / 1000}s) before next poll...`,
   203→      );
   204→      await sleep(delay);
   205→      logger.debug(
   206→        `[POLLING] ✅ Woke up after ${delay}ms sleep. Time elapsed: ${Math.round((Date.now() - start) / 1000)}s`,
   207→      );
   208→    } catch (error) {
   209→      // [warn] network or parse error, continue with backoff
   210→      logger.debug(`[POLLING] 💥 Request failed on attempt ${attempt}:`, {
   211→        error: error instanceof Error ? error.message : error,
   212→        errorType:
   213→          error instanceof Error ? error.constructor.name : typeof error,
   214→        predictionId,
   215→        provider,
   216→        attempt,
   217→      });
