   222→      }
   223→
   224→      const delay = fixedInterval
   225→        ? initialDelayMs
   226→        : backoff(attempt - 1, initialDelayMs, maxDelayMs);
   227→      logger.debug(`[POLLING] ⏰ Waiting ${delay}ms before retry...`, {
   228→        mode: fixedInterval ? "fixed-interval" : "exponential-backoff",
   229→      });
   230→      await sleep(delay);
   231→    }
   232→  }
   233→
   234→  // [error] Timed out
   235→  logger.debug(
   236→    `[POLLING] ⏰ TIMEOUT: Polling timed out after ${maxAttempts} attempts`,
   237→    {
   238→      predictionId,
   239→      totalTime: `${Math.round((Date.now() - start) / 1000)}s`,
   240→      maxAttempts,
   241→      totalTimeoutMs: `${totalTimeoutMs / 1000}s`,
   242→    },
   243→  );
   244→
   245→  return { id: predictionId, status: "failed", error: "Polling timed out" };
   246→}
