     4→/**
     5→ * Fetch a prompt from Langfuse Prompt Management with automatic fallback.
     6→ *
     7→ * This function attempts to fetch a prompt from Langfuse using the production label.
     8→ * If Langfuse is unavailable or the prompt doesn't exist, it falls back to the
     9→ * provided hardcoded prompt to ensure zero downtime.
    10→ *
    11→ * @param promptName - The name of the prompt in Langfuse (e.g., "main_agent_prompt")
    12→ * @param fallbackPrompt - The hardcoded prompt to use if Langfuse fetch fails
    13→ * @returns The prompt content (either from Langfuse or fallback)
    14→ *
    15→ * @example
    16→ * ```typescript
    17→ * const prompt = await getPromptWithFallback(
    18→ *   "main_agent_prompt",
    19→ *   main_agent_prompt
    20→ * );
    21→ * ```
    22→ */
    23→export async function getPromptWithFallback(
    24→  promptName: string,
    25→  fallbackPrompt: string
    26→): Promise<string> {
    27→  try {
    28→    // Fetch prompt from Langfuse (production label by default)
    29→    const promptData = await langfuse.prompt.get(promptName, {
    30→      type: "text",
    31→    });
    32→
    33→    // Extract the prompt content
    34→    const promptContent = promptData.prompt;
    35→
    36→    logger.info(`[Langfuse] Successfully fetched prompt: ${promptName}`);
    37→    return promptContent;
    38→  } catch (error) {
    39→    // Log warning and fall back to hardcoded prompt
    40→    const errorMessage = error instanceof Error ? error.message : String(error);
    41→    logger.warn(
    42→      `[Langfuse] Failed to fetch prompt "${promptName}", using fallback. Error: ${errorMessage}`
    43→    );
    44→
    45→    return fallbackPrompt;
    46→  }
    47→}
