// src/lib/agents/middleware/error-handler.ts
import logger from "@/utils/logger";

/**
 * Error context for agent operations.
 */
export interface AgentErrorContext {
  requestId?: string;
  userId?: string;
  chatId?: string;
  operation?: string;
}

/**
 * Standardized error response for agent operations.
 */
export interface AgentErrorResponse {
  message: string;
  code?: string;
  retryable?: boolean;
}

/**
 * Maps error types to user-friendly messages.
 */
export function getErrorMessage(error: unknown): AgentErrorResponse {
  if (!(error instanceof Error)) {
    return {
      message: "Sorry, I am not able to respond right now. Please try again later.",
      code: "UNKNOWN_ERROR",
      retryable: true,
    };
  }

  const errorMessage = error.message.toLowerCase();

  if (errorMessage.includes("rate limit")) {
    return {
      message: "I'm experiencing high demand right now. Please try again in a moment.",
      code: "RATE_LIMIT",
      retryable: true,
    };
  }

  if (errorMessage.includes("timeout")) {
    return {
      message: "The request took too long. Please try a simpler question.",
      code: "TIMEOUT",
      retryable: true,
    };
  }

  if (errorMessage.includes("context length")) {
    return {
      message: "The conversation is too long. Please start a new chat.",
      code: "CONTEXT_LENGTH",
      retryable: false,
    };
  }

  if (errorMessage.includes("authentication") || errorMessage.includes("unauthorized")) {
    return {
      message: "Authentication failed. Please sign in again.",
      code: "AUTH_ERROR",
      retryable: false,
    };
  }

  return {
    message: "Sorry, I am not able to respond right now. Please try again later.",
    code: "GENERAL_ERROR",
    retryable: true,
  };
}

/**
 * Logs agent errors with context.
 */
export function logAgentError(
  error: unknown,
  context: AgentErrorContext,
): void {
  const errorMessage = error instanceof Error ? error.message : String(error);
  const stack = error instanceof Error ? error.stack : undefined;

  logger.error(
    `Agent error: ${errorMessage}`,
    {
      ...context,
      stack,
      errorType: error instanceof Error ? error.constructor.name : typeof error,
    },
  );
}

/**
 * Creates a standardized error handler for stream operations.
 */
export function createStreamErrorHandler(context: AgentErrorContext) {
  return (error: unknown): string => {
    logAgentError(error, context);
    const response = getErrorMessage(error);
    return response.message;
  };
}
```

